const records = $input.all();

const result = records.reduce((acc, item) => {
  const data = item.json;
  const prices = data.price?.items ?? [];

  const quantityPrice = prices.find(p => p?.priceLevelName === "Quantity")?.price ?? null;

  acc.push({
    Name: data.itemId,
    External_ID__c: data.id,
    IsActive: data.isinactive === "F",
    PricebookEntry_Price__c: quantityPrice
  });

  return acc;
}, []);

return result.map(r => ({ json: r }));
